const Q_CHEMISTRY_2020_MODEL_II=[{"id": "objective>Chemistry>2020-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equations does not illustrate correctly one of the reactions of chlorine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2HCl + S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2NaOH → NaCl + NaClO + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2NaF → 2NaCl + F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CaOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation Cl2 + 2NaF → 2NaCl + F2 does not illustrate correctly one of the reactions of chlorine. <br/>  <br/> In this reaction, chlorine reacts with sodium fluoride to form sodium chloride and fluorine gas. However, this reaction is not possible because fluorine is a much more reactive element than chlorine. When chlorine and fluorine react, they form a compound called chlorine trifluoride (ClF3), which is a very powerful oxidizing agent.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2020-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The molecule that has a non-polar covalent bond is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, the two chlorine atoms are identical and have the same electronegativity. Since both atoms have the same electronegativity, the electrons in the covalent bond are shared equally, resulting in a non-polar covalent bond. The molecule does not have a significant separation of charge and lacks a permanent dipole moment.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2020-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of oxygen is produced from the decomposition of 2 mole of KCIO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> at s.t.p? <br/> [Molar volume of a gas at s.t.p = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.6 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">44.8 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">67.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">balanced equation; <br/> 2KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → 2KCl + 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 3 moles of oxygen is produced <br/> 1 moles of oxygen is 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at stp <br/> 3 moles of oxygen is 67.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2020-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent substance are used for <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cooling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wetting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Melting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drying</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescence is when a compound absorb a large amount of water on exposure to the atmosphere so they eventually turn into solutions. These substances are said to be deliquescent.They are used as drying agents, since they can absorb water E.g sodium hydroxide, calcium chloride, silica gel, iron(3)chloride,e.t.c <br/> </div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2020-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why are H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, not suitable for drying ammonia gas? They</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are corrosive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are poisonous.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">react with the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollute the gas</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H2SO4 and CaCl2 are not suitable for drying ammonia gas because they react with the gas. <br/>  <br/> Ammonia is a basic gas, and both H2SO4 and CaCl2 are acidic. When these two substances react, they form salts that contain ammonia. This can contaminate the ammonia gas and make it unusable. <br/>  <br/> In addition, H2SO4 is a corrosive substance, and CaCl2 can be harmful to breathe in. Therefore, it is not safe to use these substances to dry ammonia gas.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2020-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relative molar mass of a gaseous hydrocarbon is 30. Determine its vapour density.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vapour density = Relative molar mass / 2 <br/> Vapour density = 30 / 2 = 15 <br/> Therefore, the vapour density of the gaseous hydrocarbon is 15.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2020-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions represents the hydrolysis of an alkanoate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH  + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH  ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>  ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrolysis of an alkanoate is the reaction of an alkanoate with water to form a carboxylic acid and an alcohol. The correct reaction is: <br/>  <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2020-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about ammonium salt is correct? It</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissolves in water to form solution of pH>7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolves in water to form solution of pH< 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not decompose on heating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is insoluble in water</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonium salts dissolve in water, they form ammonium ions (NH₄⁺) and the corresponding anions. The NH₄⁺ ion is acidic and can release a proton (H⁺), thus lowering the pH of the solution.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2020-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of chromium in Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+12</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation state of Na is +1 and oxygen is -2. <br/> Thus, <br/> 2 * (+1) + 2 * (x) + 7 * (-2) = 0 <br/> 2 + 2x -14 = 0 <br/> 2x -12=0 <br/> 2x=12 <br/> x= +6</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2020-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 60 g of M combines with 24 g of oxygen, what would the empirical formula of the oxide be?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Data obtained from the question <br/> M = 60 g <br/> O = 24 g <br/> Empirical formula =? <br/> How to determine the empirical formula <br/> Divide by their molar mass <br/> M = 60÷120 = 0.5 <br/> O = 24 ÷16 = 1.5 <br/> Divide by the smallest <br/> M = 0.5÷0.5 = 1 <br/> O = 1.5 ÷0.5 = 3 <br/> Thus, the empirical formula of the oxide is MO₃</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2020-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> contravenes the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pauli's exclusion principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aufbau's principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Octet rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hund's rule</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hund's Rule: This rule states that electrons will fill degenerate orbitals (orbitals with the same energy) singly as far as possible. Each orbital in a given subshell (like 2p) gets one electron before any orbital gets a second electron, and all single electrons in degenerate orbitals have the same spin. <br/>  <br/> Analysis: <br/> The given electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> suggests that two electrons are placed in the 2p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> orbital while the 2p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> and 2p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span> orbitals remain empty. According to Hund's rule, the correct filling for the 2p orbitals should be: <br/> 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>  <br/> Each 2p orbital should get one electron before any pairing occurs. Thus, the configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> violates Hund's rule by not distributing the electrons singly across the degenerate 2p orbitals.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2020-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the quantity of electricity used  when a current of 0.20 amperes is passed through an electrolytic cell for 60 minutes.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">360C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">720C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of electricity is calculated using the formula Q = It, where Q is the charge, I is the current and t is the time. Here, I = 0.20A and t = 60 minutes = 3600 seconds. So, Q = 0.20 * 3600 = 720C.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2020-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances has the lowest boiling point?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aqueous sodium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aqueous Sodium Chloride: The boiling point is elevated compared to pure water. <br/> Ethanol: Boiling point is around 78.37°C. <br/> Tetrachloromethane: Boiling point is approximately 76.7°C. <br/> Water: Boiling point is 100°C. <br/> Among the substances listed, tetrachloromethane (carbon tetrachloride) has the lowest boiling point at approximately 76.7°C.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2020-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about the collision theory is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">All collisions bring about reactions.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate of reaction is proportional to the number of effective collisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Collision of molecules will split the molecules to react</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ineffective collision brings about chemical reaction.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of reaction is proportional to the number of effective collisions. This means that if the number of collisions increases, the rate of reaction will also increase. These successful collisions are known as effective collisions. The rate of reaction is directly proportional to the number of effective collisions between reactant molecules. In other words, the more frequent and successful the collisions, the faster the rate of the reaction.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : PHOSPHORUS"}, {"id": "objective>Chemistry>2020-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases could be collected by downward displacement of air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(IV) oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Downward displacement of air is a method used to collect gases that are less dense than air. This method involves directing the gas into an inverted container, which allows the gas to displace the air inside. Hydrogen is less dense than air. Therefore, it can be collected by downward displacement of air. This is because it rises above air and can push the air out of an inverted container.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2020-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The separation technique that is suitable for separating iodine from tetrachloromethane is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solvent extraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fractional distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solvent extraction, also known as liquid-liquid extraction, is a technique used to separate substances based on their differential solubilities in two immiscible liquids. In this case, since iodine and tetrachloromethane have different solubilities in certain solvents, you can use solvent extraction to selectively dissolve one of the substances while leaving the other behind. Iodine is a non-polar molecule, while tetrachloromethane is a polar molecule. This means that iodine will dissolve in a non-polar solvent, while tetrachloromethane will dissolve in a polar solvent.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2020-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What current in amperes will deposit 2.7g of aluminium in 2 hours? <br/> [Al = 27, F = 96 500 C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation <br/> Al <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+ </span>+ 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> --> Al <br/> 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> = 3F <br/> 3×96500 = 27 <br/> Q = 2.7 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q=</td><td style=\"text-align:center;\">3×96500×2.7<hr size=\"1\" />27 <br/> </td></tr></table></div>Q= 28950 <br/> Q=IT <br/> 28950=I × 2×60×60 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">28950<hr size=\"1\" />7200</td><td style=\"text-align:center;\">=4 <br/> </td></tr></table></div></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2020-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions represents the hydrolysis of an alkanoate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH  + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH  ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>  ⇌H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>⇌  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrolysis of an alkanoate is the reaction of an alkanoate with water to form a carboxylic acid and an alcohol. The correct reaction is: <br/>  <br/> CH3COOC2H5 + H2O ⇌H+⇌ CH3COO- + CH3CH2OH</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2020-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture containing two salts of different solubility can be separated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crystallization is a separation technique that exploits differences in the solubilities of components in a solution. When a solution is allowed to cool or evaporate under controlled conditions, one of the salts may begin to crystallize out of the solution before the other due to its lower solubility. This process can be used to separate the salts based on their differing solubilities and crystal formation.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2020-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vapour density of an organic compound with the molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, is <br/> [H=1.0, C=12.0, O= 16.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">65</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>,= (12 × 2) + (1 × 4) + (16 × 2)= 60 g/mol <br/> Vapour density = RMM/2 <br/> =60/2=30</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2020-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cleansing effect of soap is low in acidic water because of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the formation of unionized fatty acid.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the pH of the soap molecules.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anti-biodegradable effect of hydrogen ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the hardness of the acidic water.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soaps cannot be used in acidic condition because they lose their cleansing effect due to the formation of long chain fatty acids</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2020-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound contains 40.0% carbon 6.7% hydrogen and 53.3% oxygen. If the molar mass of the compound is 180, find the molecular formula. <br/> [H = 1, C = 12, O = 16]\t</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon(C) =40% Hydrogen(H) =6.7% Oxygen(O) =53.3% <br/> STEP 1: Divide by the Relative Atomic Mass(RAM) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Carbon%(C)</td><td style=\"text-align:center;\">40<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.33 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Hydrogen%(H)</td><td style=\"text-align:center;\">6.7<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.7 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Oxygen%(O)</td><td style=\"text-align:center;\"> 53.3<hr size=\"1\" />16</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.33 <br/> </td></tr></table></div>STEP 2: Divide the number by the smallest value <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Carbon(C)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.33<hr size=\"1\" />3.33</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Hydrogen(H)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.7<hr size=\"1\" />3.33</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Oxygen(O)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.33<hr size=\"1\" />3.33</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 <br/> </td></tr></table></div>C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2 </span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> RATIO: CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>0 <br/> But Relative Molecular Mass is 180 <br/> Therefore: (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)n = 180 <br/> (12 + 2 + 16)n = 180 <br/> 30n = 180 <br/> n = 6 <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2020-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following compounds are condensation polymers except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nylon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyethene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">condensation polymers are any kind of polymers whose process of polymerization involves a condensation reaction.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2020-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following statements are correct except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">energy is released when liquids change to solids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">particles move faster in the gaseous state than in the liquid state. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon atoms in gaseous methane are further apart than those in solid diamond. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is large decrease in the volume of a solid metal when pressure is applied to it.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In general, solids are relatively incompressible compared to liquids and gases. When pressure is applied to a solid, there is typically only a small change in volume. Solids have tightly packed particles with strong intermolecular forces, making them less responsive to changes in pressure. Liquids and gases, on the other hand, can undergo larger volume changes in response to pressure.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2020-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a crystalline substance that does not possess water of crystallization is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">potassium trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxocarbonate (IV).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron (II) tetraoxosulphate (VI).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium tetraoxosulphate (VI).</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chemical formula for potassium trioxonitrate (V) is KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. It is also known as potassium nitrate. This compound does not have any water molecules as part of its crystal structure, making it anhydrous. So, it is an example of a crystalline substance that does not possess water of crystallization.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2020-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oxochlorate(I) acid is used as a bleaching agent because it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a weak acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reducing agent.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a strong acid.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HOCl is unstable and decomposes to release oxygen which oxidizes the dye to form a colourless compound.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2020-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the volume of 0.100 mol of HCl in 0.250 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">400 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molarity = 0.100 mol / 0.250 mol dm3 <br/> = 0.100 mol / 0.250 dm3 * 1000 cm3/dm3 <br/> = 400 cm3 <br/> Volume (V) = Amount (n) / Concentration (C) <br/> Given that the amount of HCl is 0.100 mol and the concentration of the solution is 0.250 mol/dm³, you can calculate the volume: <br/> Volume (V) = 0.100 mol / 0.250 mol/dm³ = 0.4 dm³ <br/> Since 1 dm³ is equal to 1000 cm³, you can convert the volume from dm³ to cm³: <br/> Volume (V) = 0.4 dm³ × 1000 cm³/dm³ = 400 cm³ <br/> Therefore, the volume of 0.100 mol of HCl in a 0.250 mol/dm³ solution is 400 cm³.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2020-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following scientists formulated the law of conservation of mass?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A. Lavoisier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J. Dalton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R. Boyle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J. Proust</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Law of conservation of mass was given by Antoine Lavoisier in 1744. According to this law, \"Matter can neither be created nor destroyed in a chemical reaction\".</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2020-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compound is a normal salt? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaHS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A normal salt is a salt formed by the complete replacement of replaceable hydrogen atoms from an acid molecule by means of a metal or a group of elements acting like a metal.Eg NaCl ,Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3 </span>etc <br/> Also the presence of H(hydrogen) shows that the salt is an acidic salt . <br/> </div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2020-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dilute trioxonitrate (V) acid does not produce hydrogen when it reacts with metals because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is a strong oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it reacts with the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no visible reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is highly corrosive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dilute trioxonitrate (V) acid does not produce hydrogen when it reacts with metals because it is a strong oxidizing agent. <br/>  <br/> Trioxonitrate (V) acid, also known as nitric acid, is a strong oxidizing agent. This means that it can easily oxidize metals, which means that it can remove electrons from metals. When nitric acid oxidizes a metal, it forms a salt and water. The salt does not contain hydrogen, so no hydrogen gas is produced</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2020-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles are there in 3.0 g of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>? [O = 16.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.0093</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0930</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0625</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Number of moles = Mass / Molar mass <br/>  <br/> Given that the molar mass of oxygen (O2) is 32.0 g/mol (2 × 16.0 g/mol), you can calculate the number of moles: <br/>  <br/> Number of moles = 3.0 g / 32.0 g/mol = 0.09375 moles <br/>  <br/> Rounded to four significant figures, the number of moles in 3.0 g of O2 is approximately 0.0938 moles. <br/>  <br/> Therefore, the closest answer choice is: <br/> 0.0930 moles.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2020-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium hydroxide is used in the dyeing industry as a <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mordant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dispersant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminum hydroxide is also used as a mordant in dyeing. In most cases, the compound is precipitated out of a water solution onto the fibers to be dyed. The material is then immersed into the dye bath. The color of the final product depends on the combination of dye and mordant used in the process. A similar process is used in the manufacture of certain paint pigments. <br/> </div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2020-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reduction half equation of the following reaction is: <br/> Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>  → Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>  + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">he reduction half equation for the given reaction is: <br/>  <br/> Cu2+(aq) + 2e- → Cu(s) <br/>  <br/> In the overall reaction, copper(II) ions (Cu2+) gain two electrons (2e-) and get reduced to form solid copper (Cu) metal. This is the reduction half-reaction in the redox reaction between zinc (Zn) and copper(II) sulfate (CuSO4). </div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2020-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first definition of an element was made by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">J. Dalton.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A. Lavoisier.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R. Boyle.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J. J. Thompson.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word element was first given by Rebert Boyle. It is defined as the simplest chemical substance that cannot be broken down during a chemical reaction.</div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2020-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Charcoal is used in the decolourization of sugar because of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorption property.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amorphous property.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidizing property.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adsorption property.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wood charcoal is used to decolourise sugar because it has a highly porous structure, providing a large surface area for adsorption. Therefore, it adsorbs coloured material from sugar.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2020-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the statements about gases is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The total kinetic energy of the gas is not affected by collision.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molecules of the gas are in constant motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gases have low densities compared to solids and liquids of equal mass.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gases are highly soluble in water at high temperatures</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The statement that is not correct about gases is Gases are highly soluble in water at high temperatures. <br/>  <br/> Gases are not highly soluble in water at high temperatures. In fact, the solubility of gases in water decreases as the temperature increases. This is because the kinetic energy of the gas molecules increases as the temperature increases. The increased kinetic energy of the gas molecules makes it more difficult for them to be dissolved in water.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2020-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Arrange the following compounds in decreasing order of their boiling points: NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HF, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>,CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, HF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HF,NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, HF, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of boiling points of the compounds NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HF, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is HF, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, SiH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. <br/>  <br/> The boiling point of a compound is the temperature at which the vapor pressure of the liquid is equal to the atmospheric pressure. The stronger the intermolecular forces, the higher the boiling point.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2020-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the statements about gases is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The total kinetic energy of the gas is not affected by collision.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molecules of the gas are in constant motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gases have low densities compared to solids and liquids of equal mass.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gases are highly soluble in water at high temperatures</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The statement that is not correct about gases is Gases are highly soluble in water at high temperatures. <br/>  <br/> Gases are not highly soluble in water at high temperatures. In fact, the solubility of gases in water decreases as the temperature increases. This is because the kinetic energy of the gas molecules increases as the temperature increases. The increased kinetic energy of the gas molecules makes it more difficult for them to be dissolved in water.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2020-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanedioic acid is an organic solid that can be purified by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an effective method for purifying solids. In this process, the solid is dissolved in a suitable solvent to form a solution. As the solution cools, the pure solid crystallizes out, leaving impurities in the solution. Ethanedioic acid can be purified using this method by dissolving it in hot water and then allowing it to recrystallize upon cooling.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2020-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name of the compound Br(Cl)CHCF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-chloro-2-bromo-1,1,1-trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-bromo-2-chloro-1,1,1-trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1-bromo-1-chloro-2,2,2-trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,1,1-trifluoro-2-bromo-2-chloroethane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: CF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHBrCl <br/> <img src=\"2020-Model-II/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> 1-bromo-1-chloro-2,2,2-trifluoroethane</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}];
